## Configuration Validation

Validate configuration before execution:

```python
class ConfigValidator:
    """Validate data source configuration."""

    VALID_CONSISTENCY_LEVELS = {
        "ONE", "TWO", "THREE", "QUORUM", "ALL",
        "LOCAL_QUORUM", "EACH_QUORUM", "LOCAL_ONE"
    }

    VALID_COMPRESSION = {
        "none", "gzip", "snappy", "lz4", "zstd"
    }

    @classmethod
    def validate(cls, options):
        """Validate all configuration options."""
        errors = []

        # Validate consistency level
        if "consistency" in options:
            consistency = options["consistency"].upper()
            if consistency not in cls.VALID_CONSISTENCY_LEVELS:
                errors.append(
                    f"Invalid consistency level '{consistency}'. "
                    f"Valid: {', '.join(cls.VALID_CONSISTENCY_LEVELS)}"
                )

        # Validate compression
        if "compression" in options:
            compression = options["compression"].lower()
            if compression not in cls.VALID_COMPRESSION:
                errors.append(
                    f"Invalid compression '{compression}'. "
                    f"Valid: {', '.join(cls.VALID_COMPRESSION)}"
                )

        # Validate numeric ranges
        if "timeout" in options:
            timeout = int(options["timeout"])
            if timeout < 0 or timeout > 300:
                errors.append(f"timeout must be 0-300 seconds, got {timeout}")

        if "batch_size" in options:
            batch_size = int(options["batch_size"])
            if batch_size < 1 or batch_size > 10000:
                errors.append(f"batch_size must be 1-10000, got {batch_size}")

        # Validate dependent options
        if options.get("ssl_enabled", "false").lower() == "true":
            if "ssl_ca_cert" not in options:
                errors.append("ssl_ca_cert required when ssl_enabled=true")

        if errors:
            raise ValueError("Configuration errors:\n" + "\n".join(f"- {e}" for e in errors))
```

## Resource Cleanup

Ensure proper resource cleanup:

```python
class ManagedResourceWriter:
    """Writer with guaranteed resource cleanup."""

    def __init__(self, options):
        self.options = options
        self._connection = None
        self._session = None

    def _get_connection(self):
        """Lazy connection initialization."""
        if self._connection is None:
            self._connection = self._create_connection()
        return self._connection

    def write(self, iterator):
        """Write with guaranteed cleanup."""
        try:
            connection = self._get_connection()

            for row in iterator:
                self._send_data(connection, row)

        finally:
            # Always cleanup resources
            self._cleanup()

    def _cleanup(self):
        """Clean up resources."""
        if self._session:
            try:
                self._session.close()
            except Exception as e:
                logger.warning(f"Error closing session: {e}")
            finally:
                self._session = None

        if self._connection:
            try:
                self._connection.close()
            except Exception as e:
                logger.warning(f"Error closing connection: {e}")
            finally:
                self._connection = None

    def __del__(self):
        """Cleanup on garbage collection."""
        self._cleanup()
```

## Health Checks

Monitor system health:

```python
class HealthCheckMixin:
    """Mixin for health check functionality."""

    def check_health(self):
        """Perform health check before operations."""
        checks = {
            "connection": self._check_connection(),
            "authentication": self._check_authentication(),
            "rate_limit": self._check_rate_limit(),
            "disk_space": self._check_disk_space()
        }

        failed = [name for name, passed in checks.items() if not passed]

        if failed:
            raise Exception(f"Health check failed: {', '.join(failed)}")

        return checks

    def _check_connection(self):
        """Check connection to external system."""
        try:
            self._test_connection()
            return True
        except Exception as e:
            logger.error(f"Connection check failed: {e}")
            return False

    def _check_authentication(self):
        """Check authentication is valid."""
        try:
            self._verify_credentials()
            return True
        except Exception as e:
            logger.error(f"Authentication check failed: {e}")
            return False

    def _check_rate_limit(self):
        """Check if under rate limits."""
        # Check current rate usage
        current_rate = self._get_current_rate()
        limit = self._get_rate_limit()

        return current_rate < limit * 0.8  # 80% threshold

    def _check_disk_space(self):
        """Check available disk space."""
        import shutil

        usage = shutil.disk_usage("/")
        free_percent = (usage.free / usage.total) * 100

        return free_percent > 10  # 10% minimum
```

## Operational Best Practices

1. **Monitoring**: Track throughput, latency, error rates
2. **Logging**: Use structured logging with correlation IDs
3. **Secrets**: Never log sensitive values, use secrets management
4. **Validation**: Validate all inputs to prevent injection attacks
5. **Resource Cleanup**: Always close connections and clean up resources
6. **Health Checks**: Verify system health before operations
7. **Rate Limiting**: Respect API rate limits with backoff
8. **Alerting**: Set up alerts for error rates and latency
9. **Documentation**: Document all configuration options
10. **Version Control**: Tag releases and maintain changelog

# Type Conversion

Bidirectional mapping between Spark types and external system types.

## Spark to External System

Convert Spark/Python values to external system types:

```python
def convert_spark_to_external(value, external_type):
    """Convert Spark/Python value to external system type."""
    if value is None:
        return None

    external_type_lower = external_type.lower()

    # UUID conversion
    if "uuid" in external_type_lower:
        import uuid
        if isinstance(value, uuid.UUID):
            return value
        return uuid.UUID(str(value))

    # Timestamp conversion
    if "timestamp" in external_type_lower:
        from datetime import datetime
        if isinstance(value, datetime):
            return value
        if isinstance(value, str):
            return datetime.fromisoformat(value.replace("Z", "+00:00"))
        if isinstance(value, (int, float)):
            return datetime.fromtimestamp(value)

    # IP address conversion
    if "inet" in external_type_lower:
        import ipaddress
        if isinstance(value, (ipaddress.IPv4Address, ipaddress.IPv6Address)):
            return value
        return ipaddress.ip_address(str(value))

    # Decimal conversion
    if "decimal" in external_type_lower:
        from decimal import Decimal
        if isinstance(value, Decimal):
            return value
        return Decimal(str(value))

    # Collections
    if "list" in external_type_lower or "set" in external_type_lower:
        if not isinstance(value, (list, set)):
            raise ValueError(f"Expected list/set, got {type(value)}")
        return list(value)

    if "map" in external_type_lower:
        if not isinstance(value, dict):
            raise ValueError(f"Expected dict, got {type(value)}")
        return value

    # Numeric types
    if "int" in external_type_lower:
        return int(value)
    if "float" in external_type_lower or "double" in external_type_lower:
        return float(value)

    # Boolean
    if "bool" in external_type_lower:
        if isinstance(value, bool):
            return value
        if isinstance(value, str):
            return value.lower() in ("true", "1", "yes")
        return bool(value)

    # Default: return as-is
    return value
```

## External System to Spark

Convert external values to Spark types:

```python
def convert_external_to_spark(value, spark_type):
    """Convert external system value to Spark type."""
    from pyspark.sql.types import (
        StringType, IntegerType, LongType, FloatType, DoubleType,
        BooleanType, TimestampType, DateType
    )
    from datetime import datetime, date

    if value is None:
        return None

    try:
        if isinstance(spark_type, StringType):
            return str(value)

        elif isinstance(spark_type, BooleanType):
            if isinstance(value, bool):
                return value
            if isinstance(value, str):
                return value.lower() in ("true", "1", "yes")
            return bool(value)

        elif isinstance(spark_type, (IntegerType, LongType)):
            if isinstance(value, bool):
                raise ValueError("Cannot convert boolean to integer")
            return int(value)

        elif isinstance(spark_type, (FloatType, DoubleType)):
            if isinstance(value, bool):
                raise ValueError("Cannot convert boolean to float")
            return float(value)

        elif isinstance(spark_type, TimestampType):
            if isinstance(value, datetime):
                return value
            if isinstance(value, str):
                return datetime.fromisoformat(value.replace("Z", "+00:00"))
            raise ValueError(f"Cannot convert {type(value)} to timestamp")

        elif isinstance(spark_type, DateType):
            if isinstance(value, date) and not isinstance(value, datetime):
                return value
            if isinstance(value, datetime):
                return value.date()
            if isinstance(value, str):
                return datetime.fromisoformat(value.replace("Z", "+00:00")).date()
            raise ValueError(f"Cannot convert {type(value)} to date")

        else:
            return value

    except (ValueError, TypeError) as e:
        raise ValueError(
            f"Failed to convert '{value}' (type: {type(value).__name__}) "
            f"to {spark_type}: {e}"
        )
```

## Cassandra-Specific Types

Handle Cassandra complex types:

```python
def convert_cassandra_to_spark(value):
    """Handle Cassandra-specific complex types."""
    if value is None:
        return None

    from cassandra.util import (
        Date, Time, Duration, OrderedMap, SortedSet,
        Point, LineString, Polygon
    )
    import uuid

    # Cassandra Date to Python date
    if isinstance(value, Date):
        return value.date()

    # Cassandra Time to nanoseconds (LongType)
    if isinstance(value, Time):
        return value.nanosecond

    # UUID to string
    if isinstance(value, uuid.UUID):
        return str(value)

    # Duration to structured dict
    if isinstance(value, Duration):
        return {
            "months": value.months,
            "days": value.days,
            "nanoseconds": value.nanoseconds
        }

    # OrderedMap to dict
    if isinstance(value, OrderedMap):
        return dict(value)

    # SortedSet to list
    if isinstance(value, SortedSet):
        return list(value)

    # Geospatial types to WKT string
    if isinstance(value, (Point, LineString, Polygon)):
        return str(value)

    return value
```

## Schema Inference

Infer Spark types from Python values:

```python
def infer_spark_type(value):
    """Infer Spark type from Python value."""
    from pyspark.sql.types import (
        StringType, IntegerType, LongType, FloatType, DoubleType,
        BooleanType, TimestampType, DateType
    )
    from datetime import datetime, date

    if value is None:
        return StringType()

    # Check bool before int (bool is subclass of int)
    if isinstance(value, bool):
        return BooleanType()

    if isinstance(value, int):
        return LongType()

    if isinstance(value, float):
        return DoubleType()

    if isinstance(value, datetime):
        return TimestampType()

    if isinstance(value, date):
        return DateType()

    # Default to string
    return StringType()
```

## External Type to Spark Type Mapping

Map external system types to Spark types:

```python
def map_external_type_to_spark(external_type):
    """Map external system types to Spark types."""
    from pyspark.sql.types import (
        StringType, IntegerType, LongType, FloatType, DoubleType,
        BooleanType, TimestampType, DateType, BinaryType
    )

    type_str = str(external_type).lower()

    # String types
    if any(t in type_str for t in ["varchar", "text", "char", "string", "uuid"]):
        return StringType()

    # Integer types
    if "int" in type_str and "big" not in type_str:
        return IntegerType()
    if "bigint" in type_str or "long" in type_str:
        return LongType()

    # Floating point
    if "float" in type_str:
        return FloatType()
    if "double" in type_str or "decimal" in type_str:
        return DoubleType()

    # Boolean
    if "bool" in type_str:
        return BooleanType()

    # Temporal types
    if "timestamp" in type_str:
        return TimestampType()
    if "date" in type_str:
        return DateType()

    # Binary
    if "blob" in type_str or "binary" in type_str:
        return BinaryType()

    # Default fallback
    return StringType()
```

